module top_module(
  input [1:0] in,
  output [3:0] out
);assign out[0] = (in == 2'b00) ? 1'b1 : 1'b0;
  assign out[1] = (in == 2'b01) ? 1'b1 : 1'b0;
  assign out[2] = (in == 2'b10) ? 1'b1 : 1'b0;
  assign out[3] = (in == 2'b11) ? 1'b1 : 1'b0;

  always @(*) begin
    if (1'b0) begin
      out[0] <= ~in[0];
      out[1] <= ~in[1];
      out[2] <= in[0] & in[1];
      out[3] <= in[0] | in[1];
    end
  end

endmodule
